const msg = $input.first().json;

// Ignore messages from bots (prevent infinite loops)
if (msg.author && msg.author.bot) {
  return [];
}

// Only respond if message has content
if (!msg.content || msg.content.trim() === '') {
  return [];
}

const channelId = msg.channelId || msg.channel_id;
const content   = msg.content.trim();
const username  = msg.author?.username || 'Therrance';

const claudePayload = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: `You are Thurnos Prime — the AI operating brain of Thurr Solutions, owned by Therrance Carrothers. You are running on Therrance's private Mac Mini.\n\nYour role: Help Therrance manage his automation agency, n8n workflows, clients, finances, and daily operations. You are sharp, direct, and practical. You remember context across the conversation.\n\nKey context:\n- Therrance runs Thurr Solutions (automation agency) and is an intern at Maximax Automation Agency\n- Active client: RESTORE-C (Weather Stopper roofing contractor)\n- n8n Cloud instance: therrancecarrothers.app.n8n.cloud\n- Lead Qualification workflow ID: qG6B8b5kwP5zmJKm\n- Sales Proposal workflow ID: Iar5xzG6KaCj8Gy2\n- API optimization priority: batch calls, pre-filter before LLM steps, use cheapest capable model\n\nRules:\n- Never send information out or make purchases without explicit consent\n- Be concise on Discord — use bullet points and short paragraphs\n- If asked to build something, give the plan first before executing`,
  messages: [
    {
      role: 'user',
      content: content
    }
  ]
};

return [{
  json: {
    channelId,
    username,
    claudePayload: JSON.stringify(claudePayload)
  }
}];

const response = $input.first().json;
const channelId = $('Filter & Prepare').first().json.channelId;

// Extract text from Claude response
const text = response.content?.[0]?.text || 'Sorry, I had trouble generating a response.';

// Discord message limit is 2000 chars — split if needed
const chunks = [];
if (text.length <= 1900) {
  chunks.push(text);
} else {
  // Split on paragraph breaks to keep responses readable
  const paragraphs = text.split('\n\n');
  let current = '';
  for (const p of paragraphs) {
    if ((current + '\n\n' + p).length > 1900) {
      if (current) chunks.push(current.trim());
      current = p;
    } else {
      current = current ? current + '\n\n' + p : p;
    }
  }
  if (current) chunks.push(current.trim());
}

return chunks.map(chunk => ({
  json: {
    channelId,
    payload: JSON.stringify({ content: chunk })
  }
}));
